const assets = [
  // === UNIT SPRITES (14 weapon/vehicle icons) ===
  { name: 'sword', file: 'units/sword.png', suffix: 'single Chinese jian straight sword, bronze blade with jade handle, ink wash style, weapon icon' },
  { name: 'spear', file: 'units/spear.png', suffix: 'single Chinese qiang spear, long wooden shaft with steel tip and red tassel, weapon icon' },
  { name: 'halberd', file: 'units/halberd.png', suffix: 'single Chinese ji halberd, crescent blade on pole, bronze and wood, weapon icon' },
  { name: 'bow', file: 'units/bow.png', suffix: 'single Chinese recurve bow with bamboo arrows, horn and sinew composite bow, weapon icon' },
  { name: 'crossbow', file: 'units/crossbow.png', suffix: 'single Chinese nu crossbow, repeating crossbow mechanism, bronze trigger, weapon icon' },
  { name: 'shield', file: 'units/shield.png', suffix: 'single Chinese round shield, lacquered wood with bronze boss and tiger motif, armor icon' },
  { name: 'horse', file: 'units/horse.png', suffix: 'single war horse silhouette, armored Chinese cavalry horse, side view, ink wash style' },
  { name: 'chariot', file: 'units/chariot.png', suffix: 'single Chinese war chariot, two-wheeled bronze chariot with canopy, vehicle icon, top-down' },
  { name: 'siege_ram', file: 'units/siege_ram.png', suffix: 'single battering ram, wooden siege ram with iron head, covered frame, siege weapon icon' },
  { name: 'trebuchet', file: 'units/trebuchet.png', suffix: 'single Chinese trebuchet, counterweight siege engine, wooden frame, siege weapon icon' },
  { name: 'war_drum', file: 'units/war_drum.png', suffix: 'single large Chinese war drum, taiko-style drum on wooden stand with red lacquer, instrument icon' },
  { name: 'banner', file: 'units/banner.png', suffix: 'single Chinese military banner, red silk flag with golden dragon emblem on bamboo pole, flag icon' },
  { name: 'supply_cart', file: 'units/supply_cart.png', suffix: 'single Chinese supply wagon, wooden ox-cart loaded with grain sacks and barrels, vehicle icon' },
  { name: 'fire_arrow', file: 'units/fire_arrow.png', suffix: 'single flaming arrow, arrow wrapped in oil-soaked cloth on fire, projectile icon, glowing' }
];

const items = assets.map((asset, i) => ({
  json: {
    ...asset,
    category: 'units',
    prompt: `${$input.first().json.style_prefix}, ${asset.suffix}`,
    negative_prompt: $input.first().json.negative_prompt,
    seed: parseInt($input.first().json.seed_base) + i,
    cfg_scale: parseFloat($input.first().json.cfg_scale),
    steps: parseInt($input.first().json.steps),
    width: parseInt($input.first().json.width),
    height: parseInt($input.first().json.height),
    model: $input.first().json.model,
    output_path: `public/assets/sprites/${asset.file}`
  }
}));

return items;

const terrainTypes = [
  { type: 'grassland', suffix: 'flat grassland tile, green grass with small wildflowers, earth tones, seamless texture' },
  { type: 'forest', suffix: 'dense forest canopy tile, bamboo and pine trees from above, dark green foliage, seamless' },
  { type: 'mountain', suffix: 'rocky mountain tile, jagged grey peaks with snow caps, ink wash mountain style, seamless' },
  { type: 'water', suffix: 'river water tile, flowing blue-green water with ripples, ink wash water style, seamless' },
  { type: 'marsh', suffix: 'marshy wetland tile, muddy water with reeds and cattails, murky brown-green, seamless' },
  { type: 'desert', suffix: 'sandy desert tile, yellow-tan sand dunes with wind patterns, arid earth tones, seamless' },
  { type: 'farmland', suffix: 'cultivated rice paddy tile, neat rows of green rice plants in water, agricultural, seamless' },
  { type: 'road', suffix: 'dirt road tile, packed brown earth path with wheel ruts, stone-lined edges, seamless' },
  { type: 'bridge', suffix: 'wooden bridge tile, Chinese arched bridge planks from above, timber and rope, seamless' },
  { type: 'fortification', suffix: 'stone wall tile, Chinese rammed earth fortification from above, grey-brown stone blocks, seamless' }
];

const variants = [0, 1, 2, 3];
const assets = [];

for (const terrain of terrainTypes) {
  for (const v of variants) {
    assets.push({
      name: `${terrain.type}_v${v}`,
      file: `terrain/${terrain.type}_v${v}.png`,
      suffix: `${terrain.suffix}, variant ${v + 1}`,
      type: terrain.type,
      variant: v
    });
  }
}

const items = assets.map((asset, i) => ({
  json: {
    ...asset,
    category: 'terrain',
    prompt: `${$input.first().json.style_prefix}, ${asset.suffix}`,
    negative_prompt: $input.first().json.negative_prompt,
    seed: parseInt($input.first().json.seed_base) + 100 + i,
    cfg_scale: parseFloat($input.first().json.cfg_scale),
    steps: parseInt($input.first().json.steps),
    width: parseInt($input.first().json.width),
    height: parseInt($input.first().json.height),
    model: $input.first().json.model,
    output_path: `public/assets/sprites/${asset.file}`
  }
}));

return items;

const assets = [
  { name: 'icon_attack', file: 'ui/icon_attack.png', suffix: 'attack command icon, crossed Chinese swords, red accent, minimal UI icon' },
  { name: 'icon_defend', file: 'ui/icon_defend.png', suffix: 'defend command icon, Chinese shield with wall, blue accent, minimal UI icon' },
  { name: 'icon_move', file: 'ui/icon_move.png', suffix: 'move command icon, running footprints arrow, green accent, minimal UI icon' },
  { name: 'icon_retreat', file: 'ui/icon_retreat.png', suffix: 'retreat command icon, backward arrow with dust cloud, yellow accent, minimal UI icon' },
  { name: 'icon_morale', file: 'ui/icon_morale.png', suffix: 'morale indicator icon, Chinese character for courage (勇) in circle, gold accent, UI icon' },
  { name: 'icon_supply', file: 'ui/icon_supply.png', suffix: 'supply indicator icon, grain sack with rice, brown accent, minimal UI icon' },
  { name: 'icon_fatigue', file: 'ui/icon_fatigue.png', suffix: 'fatigue indicator icon, tired moon/ZZZ symbol, purple accent, minimal UI icon' },
  { name: 'icon_weather_clear', file: 'ui/icon_weather_clear.png', suffix: 'clear weather icon, bright sun with rays, warm yellow, minimal UI icon' },
  { name: 'icon_weather_rain', file: 'ui/icon_weather_rain.png', suffix: 'rain weather icon, dark cloud with raindrops, blue-grey, minimal UI icon' },
  { name: 'icon_weather_fog', file: 'ui/icon_weather_fog.png', suffix: 'fog weather icon, misty swirls, light grey layers, minimal UI icon' }
];

const items = assets.map((asset, i) => ({
  json: {
    ...asset,
    category: 'ui',
    prompt: `${$input.first().json.style_prefix}, ${asset.suffix}`,
    negative_prompt: $input.first().json.negative_prompt,
    seed: parseInt($input.first().json.seed_base) + 200 + i,
    cfg_scale: parseFloat($input.first().json.cfg_scale),
    steps: parseInt($input.first().json.steps),
    width: parseInt($input.first().json.width),
    height: parseInt($input.first().json.height),
    model: $input.first().json.model,
    output_path: `public/assets/sprites/${asset.file}`
  }
}));

return items;

// When category is 'all', we generate all asset lists combined
const style_prefix = $input.first().json.style_prefix;
const negative_prompt = $input.first().json.negative_prompt;
const seed_base = parseInt($input.first().json.seed_base);
const cfg_scale = parseFloat($input.first().json.cfg_scale);
const steps = parseInt($input.first().json.steps);
const width = parseInt($input.first().json.width);
const height = parseInt($input.first().json.height);
const model = $input.first().json.model;

// Unit assets
const units = [
  { name: 'sword', file: 'units/sword.png', suffix: 'single Chinese jian straight sword, bronze blade with jade handle, ink wash style, weapon icon' },
  { name: 'spear', file: 'units/spear.png', suffix: 'single Chinese qiang spear, long wooden shaft with steel tip and red tassel, weapon icon' },
  { name: 'halberd', file: 'units/halberd.png', suffix: 'single Chinese ji halberd, crescent blade on pole, bronze and wood, weapon icon' },
  { name: 'bow', file: 'units/bow.png', suffix: 'single Chinese recurve bow with bamboo arrows, horn and sinew composite bow, weapon icon' },
  { name: 'crossbow', file: 'units/crossbow.png', suffix: 'single Chinese nu crossbow, repeating crossbow mechanism, bronze trigger, weapon icon' },
  { name: 'shield', file: 'units/shield.png', suffix: 'single Chinese round shield, lacquered wood with bronze boss and tiger motif, armor icon' },
  { name: 'horse', file: 'units/horse.png', suffix: 'single war horse silhouette, armored Chinese cavalry horse, side view, ink wash style' },
  { name: 'chariot', file: 'units/chariot.png', suffix: 'single Chinese war chariot, two-wheeled bronze chariot with canopy, vehicle icon, top-down' },
  { name: 'siege_ram', file: 'units/siege_ram.png', suffix: 'single battering ram, wooden siege ram with iron head, covered frame, siege weapon icon' },
  { name: 'trebuchet', file: 'units/trebuchet.png', suffix: 'single Chinese trebuchet, counterweight siege engine, wooden frame, siege weapon icon' },
  { name: 'war_drum', file: 'units/war_drum.png', suffix: 'single large Chinese war drum, taiko-style drum on wooden stand with red lacquer, instrument icon' },
  { name: 'banner', file: 'units/banner.png', suffix: 'single Chinese military banner, red silk flag with golden dragon emblem on bamboo pole, flag icon' },
  { name: 'supply_cart', file: 'units/supply_cart.png', suffix: 'single Chinese supply wagon, wooden ox-cart loaded with grain sacks and barrels, vehicle icon' },
  { name: 'fire_arrow', file: 'units/fire_arrow.png', suffix: 'single flaming arrow, arrow wrapped in oil-soaked cloth on fire, projectile icon, glowing' }
];

// Terrain assets
const terrainTypes = [
  { type: 'grassland', suffix: 'flat grassland tile, green grass with small wildflowers, earth tones, seamless texture' },
  { type: 'forest', suffix: 'dense forest canopy tile, bamboo and pine trees from above, dark green foliage, seamless' },
  { type: 'mountain', suffix: 'rocky mountain tile, jagged grey peaks with snow caps, ink wash mountain style, seamless' },
  { type: 'water', suffix: 'river water tile, flowing blue-green water with ripples, ink wash water style, seamless' },
  { type: 'marsh', suffix: 'marshy wetland tile, muddy water with reeds and cattails, murky brown-green, seamless' },
  { type: 'desert', suffix: 'sandy desert tile, yellow-tan sand dunes with wind patterns, arid earth tones, seamless' },
  { type: 'farmland', suffix: 'cultivated rice paddy tile, neat rows of green rice plants in water, agricultural, seamless' },
  { type: 'road', suffix: 'dirt road tile, packed brown earth path with wheel ruts, stone-lined edges, seamless' },
  { type: 'bridge', suffix: 'wooden bridge tile, Chinese arched bridge planks from above, timber and rope, seamless' },
  { type: 'fortification', suffix: 'stone wall tile, Chinese rammed earth fortification from above, grey-brown stone blocks, seamless' }
];
const terrain = [];
for (const t of terrainTypes) {
  for (let v = 0; v < 4; v++) {
    terrain.push({ name: `${t.type}_v${v}`, file: `terrain/${t.type}_v${v}.png`, suffix: `${t.suffix}, variant ${v + 1}` });
  }
}

// UI assets
const ui = [
  { name: 'icon_attack', file: 'ui/icon_attack.png', suffix: 'attack command icon, crossed Chinese swords, red accent, minimal UI icon' },
  { name: 'icon_defend', file: 'ui/icon_defend.png', suffix: 'defend command icon, Chinese shield with wall, blue accent, minimal UI icon' },
  { name: 'icon_move', file: 'ui/icon_move.png', suffix: 'move command icon, running footprints arrow, green accent, minimal UI icon' },
  { name: 'icon_retreat', file: 'ui/icon_retreat.png', suffix: 'retreat command icon, backward arrow with dust cloud, yellow accent, minimal UI icon' },
  { name: 'icon_morale', file: 'ui/icon_morale.png', suffix: 'morale indicator icon, Chinese character for courage (勇) in circle, gold accent, UI icon' },
  { name: 'icon_supply', file: 'ui/icon_supply.png', suffix: 'supply indicator icon, grain sack with rice, brown accent, minimal UI icon' },
  { name: 'icon_fatigue', file: 'ui/icon_fatigue.png', suffix: 'fatigue indicator icon, tired moon/ZZZ symbol, purple accent, minimal UI icon' },
  { name: 'icon_weather_clear', file: 'ui/icon_weather_clear.png', suffix: 'clear weather icon, bright sun with rays, warm yellow, minimal UI icon' },
  { name: 'icon_weather_rain', file: 'ui/icon_weather_rain.png', suffix: 'rain weather icon, dark cloud with raindrops, blue-grey, minimal UI icon' },
  { name: 'icon_weather_fog', file: 'ui/icon_weather_fog.png', suffix: 'fog weather icon, misty swirls, light grey layers, minimal UI icon' }
];

const all = [
  ...units.map((a, i) => ({ ...a, category: 'units', seed: seed_base + i })),
  ...terrain.map((a, i) => ({ ...a, category: 'terrain', seed: seed_base + 100 + i })),
  ...ui.map((a, i) => ({ ...a, category: 'ui', seed: seed_base + 200 + i }))
];

return all.map(asset => ({
  json: {
    ...asset,
    prompt: `${style_prefix}, ${asset.suffix}`,
    negative_prompt,
    cfg_scale,
    steps,
    width,
    height,
    model,
    output_path: `public/assets/sprites/${asset.file}`
  }
}));

// Post-process: decode base64 image from Stability AI response
// Then resize to 32x32 using Sharp (must be installed in n8n environment)
//
// If Sharp is not available, this node outputs the raw image
// and you can resize externally or use a downstream ImageMagick node.

const items = [];

for (const item of $input.all()) {
  const artifacts = item.json.artifacts || item.json.images || [];
  const artifact = artifacts[0];

  if (!artifact) {
    items.push({
      json: {
        error: `No image generated for ${item.json.name}`,
        name: item.json.name,
        output_path: item.json.output_path
      }
    });
    continue;
  }

  const base64Image = artifact.base64;
  const imageBuffer = Buffer.from(base64Image, 'base64');

  let finalBuffer;
  try {
    // Attempt Sharp resize to 32x32
    const sharp = require('sharp');
    finalBuffer = await sharp(imageBuffer)
      .resize(32, 32, {
        fit: 'contain',
        background: { r: 0, g: 0, b: 0, alpha: 0 }
      })
      .png()
      .toBuffer();
  } catch (e) {
    // Sharp not available - pass through raw image
    // User should resize manually or install Sharp in n8n
    finalBuffer = imageBuffer;
  }

  const binaryData = await this.helpers.prepareBinaryData(
    finalBuffer,
    item.json.name + '.png',
    'image/png'
  );

  items.push({
    json: {
      name: item.json.name,
      category: item.json.category,
      output_path: item.json.output_path,
      size: finalBuffer.length,
      resized: true
    },
    binary: {
      data: binaryData
    }
  });
}

return items;

// Summary node - collect results
const results = $input.all();
const summary = {
  total: results.length,
  successful: results.filter(r => !r.json.error).length,
  failed: results.filter(r => r.json.error).length,
  errors: results.filter(r => r.json.error).map(r => r.json),
  generated: results.filter(r => !r.json.error).map(r => ({
    name: r.json.name,
    path: r.json.output_path,
    size: r.json.size
  }))
};

return [{ json: summary }];
